// Formater la réponse de création de service
const response = $input.item.json.result || $input.item.json;
const data = response.data || response;

if (response.status !== 'success') {
  return {
    json: {
      success: false,
      message: `❌ Erreur lors de la création du service: ${response.msg || 'Erreur inconnue'}`,
      error: response.msg
    }
  };
}

const serviceName = data.id || data.SERVER_NAME || 'inconnu';
const isDraft = data.is_draft || false;
const status = isDraft ? '📝 brouillon' : '✅ en ligne';

let formattedText = `✅ Service **${serviceName}** créé avec succès en mode ${status}.\n\n`;
formattedText += `• Méthode: ${data.method || 'N/A'}\n`;

if (data.creation_date) {
  const date = new Date(data.creation_date).toLocaleString('fr-FR');
  formattedText += `• Créé le: ${date}\n`;
}

if (!isDraft) {
  formattedText += '\n⚠️ N\'oubliez pas de recharger la configuration avec `reload_config` pour appliquer les changements.';
} else {
  formattedText += '\n💡 Le service est en mode brouillon. Utilisez `convert_service` pour le mettre en ligne.';
}

return {
  json: {
    success: true,
    message: formattedText,
    service: data
  }
};
